+    fn from_file(path: &std::path::Path) -> Result<Self> {
+        let file = std::fs::File::open(path)
+            .map_err(|e| FrankenError::internal(format!("sorter run open: {e}")))?;
+        Ok(Self::File {
+            reader: std::io::BufReader::new(file),
+            current: None,
+        })
+    }
